import "sync"

func fanout(items []int, work func(int) int) []int {
	var wg sync.WaitGroup
	out := make([]int, len(items))
	for i, v := range items {
		wg.Add(1)
		go func(i, v int) {
			defer wg.Done()
			out[i] = work(v)
		}(i, v)
	}
	wg.Wait()
	return out
}

