pub fn count_words(text: &str) -> HashMap<String, u32> {
    let mut m: HashMap<String, u32> = HashMap::new();
    for w in text.split_whitespace() {
        if let Some(v) = m.get_mut(w) { *v += 1; } else { m.insert(w.to_string(), 1); }
    }
    m
